proof:
-- Since `secondInvo k` is an involution on `U k` with exactly 1 fixed point, by the theory of involutions on finite sets, an involution with an odd number of fixed points means the set has odd cardinality. So `card(U k)` is odd.
have hU_odd : Fintype.card (U k) % 2 = 1 := by
  -- By the properties of involutions, the number of fixed points of an involution on a finite set is congruent to the size of the set modulo 2.
  have h_involution_parity : ∀ (f : U k → U k), Function.Involutive f → (Fintype.card (U k)) % 2 = (Fintype.card {x : U k | f x = x}) % 2 := by
    intro f hf_inv
    have h_involution_parity : (Finset.filter (fun x => f x ≠ x) (Finset.univ : Finset (U k))).card % 2 = 0 := by
      -- Since $f$ is an involution, the set of elements not fixed by $f$ can be partitioned into pairs $\{x, f(x)\}$.
      have h_partition : ∃ S : Finset (Finset (U k)), (∀ s ∈ S, s.card = 2) ∧ (∀ s ∈ S, ∀ t ∈ S, s ≠ t → Disjoint s t) ∧ Finset.filter (fun x => f x ≠ x) (Finset.univ : Finset (U k)) = Finset.biUnion S id := by
        use Finset.image (fun x => {x, f x}) (Finset.filter (fun x => f x ≠ x) (Finset.univ : Finset (U k)));
        simp +zetaDelta at *;
        refine' ⟨ _, _, _ ⟩;
        · grind;
        · rintro s x y z hx hy hxy rfl t u v w hu hv huv rfl hst; simp_all +decide [ Finset.disjoint_left ] ;
          refine' ⟨ ⟨ _, _ ⟩, _, _ ⟩ <;> contrapose! hst <;> simp_all +decide [ Finset.Subset.antisymm_iff, Finset.subset_iff ];
          · exact ⟨ hf_inv _, Or.inr <| by rw [ hf_inv ] ⟩;
          · exact ⟨ Or.inr <| by rw [ ← hst, hf_inv ], by rw [ ← hst, hf_inv ] ⟩;
          · have := hf_inv ⟨ ⟨ ( x, y, z ), hx ⟩, hy ⟩ ; have := hf_inv ⟨ ⟨ ( u, v, w ), hu ⟩, hv ⟩ ; aesop;
        · ext x; simp [Finset.mem_biUnion, Finset.mem_image];
          constructor <;> intro h;
          · exact ⟨ _, _, _, x.1.2, x.2, h, Or.inl rfl ⟩;
          · rcases h with ⟨ a, b, c, h₁, h₂, h₃, rfl | rfl ⟩ <;> simp_all +decide [ hf_inv.eq_iff ];
            rw [ hf_inv ] ; tauto;
      obtain ⟨ S, hS₁, hS₂, hS₃ ⟩ := h_partition; rw [ hS₃, Finset.card_biUnion ] <;> aesop;
    have h_involution_parity : (Finset.filter (fun x => f x = x) (Finset.univ : Finset (U k))).card + (Finset.filter (fun x => f x ≠ x) (Finset.univ : Finset (U k))).card = Fintype.card (U k) := by
      rw [ Finset.card_filter_add_card_filter_not, Finset.card_univ ];
    simp +decide [ ← h_involution_parity, Nat.add_mod, ‹Finset.card { x | f x ≠ x } % 2 = 0› ];
    rw [ Fintype.card_subtype ];
  specialize h_involution_parity (fun x => secondInvo k x) (by
  exact fun x => by simpa [ sq ] using congr_arg ( fun f => f x ) ( secondInvo_sq k ) ;);
  convert h_involution_parity using 1;
  convert congr_arg ( · % 2 ) ( card_fixedPoints_eq_one k |> Eq.symm ) using 1;
exact Nat.odd_iff.mpr ( by rw [ sameCard ] at *; exact hU_odd )

